<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #1e1e2e;
            --text-color: #cdd6f4;
            --accent-color: #89b4fa;
            --button-bg: #313244;
            --button-hover: #45475a;
            --button-active: #585b70;
        }

        body {
            margin: 0;
            padding: 0;
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            min-height: 100vh;
        }

        h1 {
            margin-top: 20px;
            color: var(--accent-color);
        }

        .controls {
            margin: 20px 0;
            display: flex;
            gap: 10px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            background-color: var(--button-bg);
            color: white;
            border: none;
            padding: 10px 20px;
            font-size: 16px;
            border-radius: 5px;
            cursor: pointer;
            transition: all 0.2s ease;
            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.3);
        }

        button:hover {
            background-color: var(--button-hover);
            transform: translateY(-2px);
        }

        button:active {
            background-color: var(--button-active);
            transform: translateY(1px);
        }

        button.active {
            background-color: var(--accent-color);
            color: #1e1e2e;
            font-weight: bold;
        }

        #sand-container {
            position: relative;
            margin: 20px auto;
            box-shadow: 0 0 20px rgba(0, 0, 0, 0.5);
            border-radius: 8px;
            overflow: hidden;
        }

        canvas {
            display: block;
            cursor: crosshair;
        }

        .instructions {
            margin-top: 10px;
            font-size: 14px;
            color: #a6adc8;
            text-align: center;
            max-width: 500px;
        }
    </style>
</head>
<body>
    <h1>Falling Sand Sandbox</h1>

    <div class="controls">
        <button id="mat-sand" class="active">Sand</button>
        <button id="mat-water">Water</button>
        <button id="mat-wall">Wall</button>
        <button id="mat-acid">Acid</button>
        <button id="mat-empty">Eraser</button>
    </div>

    <div class="controls">
        <button id="clear">Clear Canvas</button>
    </div>

    <div id="sand-container">
        <canvas id="sand" width="400" height="400"></canvas>
    </div>

    <p class="instructions">
        Click and drag to paint. Sand falls, water flows, acid dissolves walls and sand.
    </p>

    <script>
        // Configuration
        const GRID_WIDTH = 80;
        const GRID_HEIGHT = 80;
        const CELL_SIZE = 5; // 400x400 canvas with 80x80 grid

        // Material constants
        const EMPTY = 0;
        const SAND = 1;
        const WATER = 2;
        const WALL = 3;
        const ACID = 4;

        // Canvas setup
        const canvas = document.getElementById('sand');
        const ctx = canvas.getContext('2d', { alpha: false });

        // Set actual canvas size to match CSS size
        canvas.width = GRID_WIDTH * CELL_SIZE;
        canvas.height = GRID_HEIGHT * CELL_SIZE;

        // Create grid
        let grid = new Uint8Array(GRID_WIDTH * GRID_HEIGHT);

        // Current material to paint (default sand)
        let currentMaterial = SAND;

        // Mouse state for painting
        let isDrawing = false;
        let mouseX = 0;
        let mouseY = 0;

        // Colors for each material
        const colors = {
            [EMPTY]: '#1e1e2e',    // Same as background
            [SAND]: '#f9e2af',     // Light sand color
            [WATER]: '#89b4fa',    // Blue
            [WALL]: '#5c5c5c',     // Gray
            [ACID]: '#a6e3a1'      // Greenish-yellow
        };

        // Helper functions to get/set grid cells
        function getIndex(x, y) {
            return y * GRID_WIDTH + x;
        }

        function getCell(x, y) {
            if (x < 0 || x >= GRID_WIDTH || y < 0 || y >= GRID_HEIGHT) {
                return WALL; // Treat out-of-bounds as wall
            }
            return grid[getIndex(x, y)];
        }

        function setCell(x, y, material) {
            if (x < 0 || x >= GRID_WIDTH || y < 0 || y >= GRID_HEIGHT) {
                return;
            }
            grid[getIndex(x, y)] = material;
        }

        // Main simulation tick
        function tick() {
            // Process from bottom to top to ensure particles move at most one cell per step
            for (let y = GRID_HEIGHT - 1; y >= 0; y--) {
                // Randomize x direction to avoid bias
                const leftToRight = Math.random() > 0.5;
                const startX = leftToRight ? 0 : GRID_WIDTH - 1;
                const endX = leftToRight ? GRID_WIDTH : -1;
                const stepX = leftToRight ? 1 : -1;

                for (let x = startX; x !== endX; x += stepX) {
                    const cell = getCell(x, y);

                    if (cell === SAND || cell === WATER || cell === ACID) {
                        // Try to move down
                        if (getCell(x, y + 1) === EMPTY) {
                            setCell(x, y + 1, cell);
                            setCell(x, y, EMPTY);
                        } else {
                            // For sand and acid: try to swap with water/acid below
                            const below = getCell(x, y + 1);
                            if ((cell === SAND || cell === ACID) && (below === WATER || below === ACID)) {
                                setCell(x, y + 1, cell);
                                setCell(x, y, below);
                            } else {
                                // Try diagonal movement
                                const dir = Math.random() > 0.5 ? 1 : -1;
                                const dx1 = dir;
                                const dx2 = -dir;

                                if (getCell(x + dx1, y + 1) === EMPTY) {
                                    setCell(x + dx1, y + 1, cell);
                                    setCell(x, y, EMPTY);
                                } else if (getCell(x + dx2, y + 1) === EMPTY) {
                                    setCell(x + dx2, y + 1, cell);
                                    setCell(x, y, EMPTY);
                                }
                            }
                        }
                    }

                    // Water spreading
                    if (cell === WATER) {
                        const below = getCell(x, y + 1);
                        if (below !== EMPTY && (below !== SAND && below !== ACID)) { // Can't fall
                            // Try to spread horizontally
                            const dir = Math.random() > 0.5 ? 1 : -1;
                            const dx1 = dir;
                            const dx2 = -dir;

                            if (getCell(x + dx1, y) === EMPTY) {
                                setCell(x + dx1, y, WATER);
                                setCell(x, y, EMPTY);
                            } else if (getCell(x + dx2, y) === EMPTY) {
                                setCell(x + dx2, y, WATER);
                                setCell(x, y, EMPTY);
                            }
                        }
                    }

                    // Acid behavior
                    if (cell === ACID) {
                        const below = getCell(x, y + 1);

                        // Try to move down or swap with water/sand/acid
                        if (below === EMPTY) {
                            setCell(x, y + 1, ACID);
                            setCell(x, y, EMPTY);
                        } else if (below === WATER || below === SAND || below === WALL) {
                            // Dissolve target and disappear
                            if (Math.random() > 0.5) { // 50% chance to dissolve
                                setCell(x, y + 1, EMPTY);
                                setCell(x, y, EMPTY);
                            } else {
                                // Try diagonal movement instead
                                const dir = Math.random() > 0.5 ? 1 : -1;
                                const dx1 = dir;
                                const dx2 = -dir;

                                if (getCell(x + dx1, y + 1) === EMPTY) {
                                    setCell(x + dx1, y + 1, ACID);
                                    setCell(x, y, EMPTY);
                                } else if (getCell(x + dx2, y + 1) === EMPTY) {
                                    setCell(x + dx2, y + 1, ACID);
                                    setCell(x, y, EMPTY);
                                }
                            }
                        } else {
                            // Try diagonal movement
                            const dir = Math.random() > 0.5 ? 1 : -1;
                            const dx1 = dir;
                            const dx2 = -dir;

                            if (getCell(x + dx1, y + 1) === EMPTY) {
                                setCell(x + dx1, y + 1, ACID);
                                setCell(x, y, EMPTY);
                            } else if (getCell(x + dx2, y + 1) === EMPTY) {
                                setCell(x + dx2, y + 1, ACID);
                                setCell(x, y, EMPTY);
                            }
                        }

                        // Acid dissolves sand and wall beside it
                        const left = getCell(x - 1, y);
                        const right = getCell(x + 1, y);

                        if (left === SAND || left === WALL) {
                            if (Math.random() > 0.5) { // 50% chance to dissolve
                                setCell(x - 1, y, EMPTY);
                            }
                        }

                        if (right === SAND || right === WALL) {
                            if (Math.random() > 0.5) { // 50% chance to dissolve
                                setCell(x + 1, y, EMPTY);
                            }
                        }
                    }
                }
            }
        }

        // Render the grid to canvas
        function render() {
            ctx.fillStyle = colors[EMPTY];
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            for (let y = 0; y < GRID_HEIGHT; y++) {
                for (let x = 0; x < GRID_WIDTH; x++) {
                    const cell = grid[getIndex(x, y)];
                    if (cell !== EMPTY) {
                        ctx.fillStyle = colors[cell];

                        // Add some variation to make it look more natural
                        if (cell === SAND || cell === WATER || cell === ACID) {
                            const shade = Math.random() > 0.9 ? 1 : 0;
                            ctx.fillStyle = adjustColor(colors[cell], shade);
                        }

                        ctx.fillRect(
                            x * CELL_SIZE, 
                            y * CELL_SIZE, 
                            CELL_SIZE, 
                            CELL_SIZE
                        );
                    }
                }
            }
        }

        // Helper to slightly darken/lighten colors for texture
        function adjustColor(color, amount) {
            let usePound = false;
            if (color[0] == "#") {
                color = color.slice(1);
                usePound = true;
            }

            const num = parseInt(color, 16);
            let r = (num >> 16) + amount;
            let g = ((num >> 8) & 0x00FF) + amount;
            let b = (num & 0x0000FF) + amount;

            // Clamp values
            r = Math.min(255, Math.max(0, r));
            g = Math.min(255, Math.max(0, g));
            b = Math.min(255, Math.max(0, b));

            return (usePound ? "#" : "") + 
                   (r.toString(16).length === 1 ? "0" + r.toString(16) : r.toString(16)) +
                   (g.toString(16).length === 1 ? "0" + g.toString(16) : g.toString(16)) +
                   (b.toString(16).length === 1 ? "0" + b.toString(16) : b.toString(16));
        }

        // Animation loop
        function animate() {
            render();
            requestAnimationFrame(animate);
        }

        // Start animation
        animate();

        // Mouse interaction for painting
        canvas.addEventListener('mousedown', (e) => {
            isDrawing = true;
            paint(e);
        });

        window.addEventListener('mouseup', () => {
            isDrawing = false;
        });

        canvas.addEventListener('mousemove', (e) => {
            if (isDrawing) {
                paint(e);
            }
        });

        function paint(e) {
            const rect = canvas.getBoundingClientRect();
            const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
            const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);

            // Paint a small brush (3x3)
            for (let dy = -1; dy <= 1; dy++) {
                for (let dx = -1; dx <= 1; dx++) {
                    if (Math.random() > 0.25) { // Add some randomness to make it look more natural
                        setCell(x + dx, y + dy, currentMaterial);
                    }
                }
            }
        }

        // Button event listeners
        document.getElementById('mat-sand').addEventListener('click', () => {
            currentMaterial = SAND;
            updateActiveButton('mat-sand');
        });

        document.getElementById('mat-water').addEventListener('click', () => {
            currentMaterial = WATER;
            updateActiveButton('mat-water');
        });

        document.getElementById('mat-wall').addEventListener('click', () => {
            currentMaterial = WALL;
            updateActiveButton('mat-wall');
        });

        document.getElementById('mat-acid').addEventListener('click', () => {
            currentMaterial = ACID;
            updateActiveButton('mat-acid');
        });

        document.getElementById('mat-empty').addEventListener('click', () => {
            currentMaterial = EMPTY;
            updateActiveButton('mat-empty');
        });

        function updateActiveButton(id) {
            // Remove active class from all buttons
            document.querySelectorAll('.controls button').forEach(btn => {
                btn.classList.remove('active');
            });

            // Add active class to selected button
            const selectedBtn = document.getElementById(id);
            if (selectedBtn) {
                selectedBtn.classList.add('active');
            }
        }

        document.getElementById('clear').addEventListener('click', () => {
            clear();
        });

        // Expose API on window
        window.sim = {
            w: GRID_WIDTH,
            h: GRID_HEIGHT,

            tick(n) {
                for (let i = 0; i < n; i++) {
                    tick();
                }
            },

            get(x, y) {
                const cell = getCell(x, y);
                switch (cell) {
                    case EMPTY: return "empty";
                    case SAND: return "sand";
                    case WATER: return "water";
                    case WALL: return "wall";
                    case ACID: return "acid";
                    default: return "empty";
                }
            },

            set(x, y, material) {
                switch (material) {
                    case "empty": setCell(x, y, EMPTY); break;
                    case "sand": setCell(x, y, SAND); break;
                    case "water": setCell(x, y, WATER); break;
                    case "wall": setCell(x, y, WALL); break;
                    case "acid": setCell(x, y, ACID); break;
                }
            },

            clear() {
                grid.fill(EMPTY);
            }
        };

        // Initialize with some sand for demonstration
        for (let i = 0; i < 100; i++) {
            const x = Math.floor(Math.random() * GRID_WIDTH);
            const y = Math.floor(Math.random() * 20); // Top area
            setCell(x, y, SAND);
        }
    </script>
</body>
</html>
